mapper.select:
SELECT ROW_NUMBER() OVER (ORDER BY A.VALT_BRNO_C, A.CNTL_CATG_C, A.CNTL_ELMN_C) AS CNT , A.CNTL_ELMN_C AS CODE_ID /*통제요소 */ , A.VALT_YYMM , A.CNTL_CATG_C /*통제범주 */ , ( SELECT DTL_C_NM FROM SRBA2_DTL_C WHERE DTL_C = A.CNTL_CATG_C AND GRP_C ='R504' ) AS CNTL_CATG_NM , A.CNTL_ELMN_C /*통제요소 */ , ( SELECT DTL_C_NM FROM SRBA2_DTL_C WHERE DTL_C = A.CNTL_ELMN_C AND GRP_C ='R505' ) AS CNTL_ELMN_NM , A.VALT_BRNO_C /* 부서코드*/ , ( SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_DESC = A.VALT_BRNO_C ) AS VALT_BRNO_NM , B.BRNO_TOCNT AS ISPT_ITEM_CNT /*전체점검수 */ , B.BRNO_VCNT AS NORM_ISPT_ITEM_CNT /*평가항목수 */ , CASE WHEN B.CNTL_EFFECT_SCORE > 99 THEN '100' ELSE TO_CHAR(B.CNTL_EFFECT_SCORE) END || '%' AS CNTL_EFFECT_SCORE /* 요소별 통제효과성 */ , C.FIX_YN , C.RECOVER_PLAN_DT , C.RECOVER_PLAN_CNTN , C.RECOVER_PLAN_C , NVL((SELECT GYLJ_RQST_G_C FROM SRBA2_GYLJ_M WHERE 1=1 AND GYLJ_ID = D.GYLJ_ID AND VALT_YYMM = D.VALT_YYMM AND ROWNUM = 1 ),'') AS GYLJ_LINE_G_C , D.GYLJ_S_C /*진행상태 */ , CASE WHEN NVL(D.GYLJ_S_C,0) IN ('1','2','4') THEN '진행중' WHEN NVL(D.GYLJ_S_C,'') = '' OR NVL(D.GYLJ_S_C,0) = 0 THEN '미진행' ELSE ( SELECT DTL_C_NM FROM SRBA2_DTL_C WHERE DTL_C = D.GYLJ_S_C AND GRP_C ='R512' ) END AS GYLJ_NM , D.GYLJ_ID , D.GYLJ_DT , D.GYLJ_JKW_NO , D.GYLJ_ROLE_ID , (SELECT TO_CHAR(ADD_MONTHS(TO_DATE(TGT_TRN_EDT, 'YYYYMMDD'), 1), 'YYYYMM') || '01' AS TGT_TRN_SDT FROM SRBA2_VLTN_SCE_D WHERE 1=1 AND VALT_YYMM = #{VALT_YYMM} AND RBA_VALT_LGDV_C = 'D' AND RBA_VALT_SMDV_C = 'D01' ) AS MIN_PLAN_DT , CASE WHEN C.VALT_YYMM IS NULL THEN 'N' ELSE 'Y' END AS WRITE_YN FROM SRBA2_CNTL_I A LEFT JOIN ( SELECT VALT_YYMM /*평가일자*/ , CNTL_CATG_C /*통제범주*/ , CNTL_ELMN_C /*통제요소*/ , VALT_BRNO_C /* 부서코드*/ , COUNT(*) AS BRNO_TOCNT /*전체점검수*/ , SUM(CASE WHEN NVL(NORM_YN,'') = '' THEN 0 ELSE NORM_YN END ) AS BRNO_VCNT /*점검수*/ , ROUND(SUM( CASE WHEN NORM_YN = 1 THEN WEIGHT ELSE 0 END ),2) AS CNTL_EFFECT_SCORE FROM SRBA2_CNTL_ITEM_I WHERE VALT_YYMM = #{VALT_YYMM} GROUP BY VALT_YYMM , CNTL_CATG_C , CNTL_ELMN_C , VALT_BRNO_C ) B ON A.VALT_YYMM = B.VALT_YYMM AND A.CNTL_CATG_C = B.CNTL_CATG_C AND A.CNTL_ELMN_C = B.CNTL_ELMN_C AND A.VALT_BRNO_C = B.VALT_BRNO_C LEFT JOIN SRBA2_CNTL_RECOVER_PLAN C ON A.VALT_YYMM = C.VALT_YYMM AND A.CNTL_CATG_C = C.CNTL_CATG_C AND A.CNTL_ELMN_C = C.CNTL_ELMN_C AND A.VALT_BRNO_C = C.VALT_BRNO_C LEFT JOIN SRBA2_GYLJ_M D ON C.VALT_YYMM = D.VALT_YYMM AND C.GYLJ_ID = D.GYLJ_ID
WHERE A.VALT_YYMM = #{VALT_YYMM} AND B.CNTL_EFFECT_SCORE < 99 /* (99.9도 만점...) 만점이 아닌 통제활동 건은 개선등록 목록에 포함 */
AND A.VALT_BRNO_C = #{VALT_BRNO}
AND A.CNTL_CATG_C = #{CNTL_CATG_C}
AND A.CNTL_ELMN_C = #{CNTL_ELMN_C}

mapper.update:
MERGE INTO SRBA2_CNTL_RECOVER_PLAN
  USING DUAL
  ON (
        VALT_YYMM = #{VALT_YYMM}
      AND CNTL_CATG_C = #{CNTL_CATG_C}
      AND CNTL_ELMN_C = #{CNTL_ELMN_C}
      AND VALT_BRNO_C = #{VALT_BRNO_C}
     )
  WHEN MATCHED THEN
UPDATE SET
       RECOVER_PLAN_C    = #{RECOVER_PLAN_C}
     , RECOVER_PLAN_DT   = #{RECOVER_PLAN_DT}
     , RECOVER_PLAN_CNTN = #{RECOVER_CNTN}
     , AC_JKW_NO         = #{AC_JKW_NO}
     , CHG_DT            = TO_CHAR(SYSDATE , 'YYYYMMDD')
     , CHG_TIME          = TO_CHAR(SYSDATE , 'HH24MISS')
     , CHG_OP_JKW_NO     = #{DR_OP_JKW_NO}
WHEN NOT MATCHED THEN
INSERT
    ( VALT_YYMM
     , CNTL_CATG_C
     , CNTL_ELMN_C
     , VALT_BRNO_C
     , RECOVER_PLAN_C
     , RECOVER_PLAN_DT
     , RECOVER_PLAN_CNTN
     , AC_JKW_NO
     , DR_DT
     , DR_TIME
     , DR_OP_JKW_NO
     )
    VALUES
    ( #{VALT_YYMM}
     , #{CNTL_CATG_C}
     , #{CNTL_ELMN_C}
     , #{VALT_BRNO_C}
     , #{RECOVER_PLAN_C}
     , #{RECOVER_PLAN_DT}
     , #{RECOVER_CNTN}
     , #{AC_JKW_NO}
     , TO_CHAR(SYSDATE , 'YYYYMMDD')
     , TO_CHAR(SYSDATE , 'HH24MISS')
     , #{DR_OP_JKW_NO}
     )

UPDATE SRBA_TONGJE_EDU_M
SET   TGT_CNT = NVL((SELECT COUNT(A.EDU_JKW_NO)
                    FROM SRBA_TONGJE_EDU_D A
                    WHERE A.VALT_YY = #{VALT_YY}
                    AND A.VALT_SDT = #{VALT_SDT}
                    AND A.EDU_M_CD = #{EDU_M_CD}
                    AND A.EDU_METH_CD = #{EDU_METH_CD}
                    AND A.EDU_TGT_CD = #{EDU_TGT_CD}
                ),0)
    , ISU_CNT = NVL((SELECT COUNT(A.EDU_JKW_NO)
                    FROM SRBA_TONGJE_EDU_D A
                    WHERE A.VALT_YY = #{VALT_YY}
                    AND A.VALT_SDT = #{VALT_SDT}
                    AND A.EDU_M_CD = #{EDU_M_CD}
                    AND A.EDU_METH_CD = #{EDU_METH_CD}
                    AND A.EDU_TGT_CD = #{EDU_TGT_CD}
                    AND A.EDU_ISU_YN = 1
                ),0)
    , CHG_DT  = TO_CHAR(SYSDATE , 'YYYYMMDD')
    , CHG_TIME = TO_CHAR(SYSDATE , 'HH24MISS')
    , CHG_OP_JKW_NO = #{OP_JKW_NO}
WHERE VALT_YY = #{VALT_YY}
AND VALT_SDT = #{VALT_SDT}
AND EDU_M_CD = #{EDU_M_CD}
AND EDU_METH_CD = #{EDU_METH_CD}
AND EDU_TGT_CD = #{EDU_TGT_CD}

MERGE INTO SRBA_TONGJE_EDU_D
USING DUAL 
ON(   VALT_YY = #{VALT_YY}
    , VALT_SDT = #{VALT_SDT}
    , EDU_M_CD = #{EDU_M_CD}
    , EDU_METH_CD = #{EDU_METH_CD}
    , EDU_TGT_CD = #{EDU_TGT_CD}
    , EDU_JKW_NO = #{EDU_JKW_NO}
)
WHEN MATCHED THEN
UPDATE SET  EDU_BRNO_CD = NVL((SELECT B.DEP_DESC FROM C_USER A LEFT OUTER JOIN C_DEP_INFO B ON A.DEP_ID = B.DEP_ID WHERE A.LOGIN_ID = #{EDU_JKW_NO}),'')
          , EDU_ISU_YN = #{EDU_ISU_YN}
          , ISU_DT = REPLACE(REPLACE(#{ISU_DT}, '/',''),'-','')
          , EDU_TIME = #{EDU_TIME}
          , MI_ISU_CD = #{MI_ISU_CD}
          , MI_ISU_NM = #{MI_ISU_NM}
          , CHG_DT        = TO_CHAR(SYSDATE , 'YYYYMMDD')
          , CHG_TIME      = TO_CHAR(SYSDATE , 'HH24MISS')
          , CHG_OP_JKW_NO = #{OP_JKW_NO}
WHEN NOT MATCHED THEN
( 
  VALT_YY
  , VALT_SDT
  , EDU_M_CD
  , EDU_METH_CD
  , EDU_TGT_CD
  , EDU_JKW_NO
  , EDU_BRNO_CD
  , EDU_ISU_YN
  , ISU_DT
  , EDU_TIME
  , MI_ISU_CD
  , MI_ISU_NM
  , DR_DT
  , DR_TIME
  , DR_OP_JKW_NO
  , CHG_DT
  , CHG_TIME
  , CHG_OP_JKW_NO
)
VALUES
(
  #{VALT_YY}
  , #{VALT_SDT}
  , #{EDU_M_CD}
  , #{EDU_METH_CD}
  , #{EDU_TGT_CD}
  , #{EDU_JKW_NO}
  , NVL((SELECT B.DEP_DESC FROM C_USER A LEFT OUTER JOIN C_DEP_INFO B ON A.DEP_ID = B.DEP_ID WHERE A.LOGIN_ID = #{EDU_JKW_NO}),'')
  , #{EDU_ISU_YN}
  , REPLACE(REPLACE(#{ISU_DT}, '/',''),'-','')
  , #{EDU_TIME}
  , #{MI_ISU_CD}
  , #{MI_ISU_NM}
  , TO_CHAR(SYSDATE , 'YYYYMMDD')
  , TO_CHAR(SYSDATE , 'HH24MISS')
  , #{OP_JKW_NO}
  , TO_CHAR(SYSDATE , 'YYYYMMDD')
  , TO_CHAR(SYSDATE , 'HH24MISS')
  , #{OP_JKW_NO}
)

