SELECT ROW_NUMBER() OVER (ORDER BY A.VALT_BRNO_C, A.CNTL_CATG_C, A.CNTL_ELMN_C) AS CNT , ( SELECT DTL_C_NM FROM SRBA2_DTL_C WHERE DTL_C = A.RECOVER_PLAN_C AND GRP_C ='R531' ) RECOVER_PLAN_NM , RECOVER_PLAN_C /* 개선계획 구분코드 */ , RECOVER_PLAN_CNTN /* 개선계획 내용 */ , AC_JKW_NO /* 조치담당자 사번 */ , GET_LOGINID_NAME(AC_JKW_NO) AS AC_JKW_NM , RECOVER_PLAN_DT /* 개선조치 계획일자 */ , NVL(NULLIF(RECOVER_OK_YN,''),'N') AS RECOVER_OK_YN /* 개선조치 완료여부 */ , RECOVER_OK_DT /* 개선조치 완료일자 */ , RECOVER_OK_CNTN /* 개선조치 완료내용 */ , A.CNTL_ELMN_C AS CODE_ID /*통제요소 */ , A.VALT_YYMM , A.CNTL_CATG_C /*통제범주 */ , ( SELECT DTL_C_NM FROM SRBA2_DTL_C WHERE DTL_C = A.CNTL_CATG_C AND GRP_C ='R504' ) CNTL_CATG_NM , A.CNTL_ELMN_C /*통제요소 */ , ( SELECT DTL_C_NM FROM SRBA2_DTL_C WHERE DTL_C = A.CNTL_ELMN_C AND GRP_C ='R505' ) CNTL_ELMN_NM , A.VALT_BRNO_C /* 부서코드*/ , ( SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_DESC = A.VALT_BRNO_C ) VALT_BRNO_NM , (SELECT TO_CHAR(ADD_MONTHS(TGT_TRN_EDT, 1), 'YYYYMM') || '01' AS TGT_TRN_SDT FROM SRBA2_VLTN_SCE_D WHERE 1=1 AND VALT_YYMM = #{VALT_YYMM,jdbcType=VARCHAR} AND RBA_VALT_LGDV_C = 'D' AND RBA_VALT_SMDV_C = 'D01' ) AS MIN_PLAN_DT FROM SRBA2_CNTL_RECOVER_PLAN A WHERE A.VALT_YYMM = #{VALT_YYMM,jdbcType=VARCHAR}
AND A.VALT_BRNO_C = #{VALT_BRNO,jdbcType=VARCHAR}
AND A.CNTL_CATG_C = #{CNTL_CATG_C, jdbcType=VARCHAR}
AND A.CNTL_ELMN_C = #{CNTL_ELMN_C, jdbcType=VARCHAR}

