UPDATE SRBA2_CNTL_RECOVER_PLAN A
   SET A.RECOVER_OK_YN   = #{RECOVER_OK_YN,     jdbcType=VARCHAR}
     , A.RECOVER_OK_CNTN = #{RECOVER_OK_CNTN,   jdbcType=VARCHAR}
     , A.RECOVER_OK_DT   = CASE WHEN #{RECOVER_OK_YN, jdbcType=VARCHAR} = 'Y' 
                                     THEN TO_CHAR(SYSDATE,'YYYYMMDD')
                                ELSE '' 
                            END 
     , CHG_DT            = TO_CHAR(SYSDATE,'YYYYMMDD')
     , CHG_TIME          = TO_CHAR(SYSDATE,'HH24MISS')
     , CHG_OP_JKW_NO     = #{CHG_OP_JKW_NO,     jdbcType=VARCHAR}
 WHERE 1=1
   AND A.VALT_YYMM   = #{VALT_YYMM,   jdbcType=VARCHAR}
   AND A.CNTL_CATG_C = #{CNTL_CATG_C, jdbcType=VARCHAR}
   AND A.CNTL_ELMN_C = #{CNTL_ELMN_C, jdbcType=VARCHAR}
   AND A.VALT_BRNO_C = #{VALT_BRNO_C, jdbcType=VARCHAR}

