          , AGREE_DT      = TO_CHAR(SYSDATE,'YYYYMMDD')
          , AGREE_NO      = #{OP_JKW_NO,jdbcType=VARCHAR}
           ,CHG_DT        = TO_CHAR(SYSDATE,'YYYYMMDD')
