           ,CHG_OP_JKW_NO = #{OP_JKW_NO,jdbcType=VARCHAR}
WHERE VALT_YYMM = #{VALT_YYMM, jdbcType=VARCHAR}

  UPDATE SRBA_TONGJE_MONTHLY_R
     SET JWN_ACTN_YN      = 1
        ,REPORT_YN        = 0
        ,PC_YN            = #{PC_YN,jdbcType=NUMERIC}
        ,CHG_DT           = TO_CHAR(SYSDATE,'YYYYMMDD')
        ,CHG_TIME         = TO_CHAR(SYSDATE,'HH24MISS')
        ,CHG_OP_JKW_NO    = #{CHG_OP_JKW_NO,jdbcType=VARCHAR}
WHERE VALT_YYMM = #{VALT_YYMM, jdbcType=VARCHAR}

mapper.select:
SELECT DTL_C    AS CD,
       DTL_C_NM AS CD_NM,
       GRP_C    AS GRP_CD
  FROM SRBA2_DTL_C  
 WHERE USYN=1

   AND GRP_C = #{GRP_C , jdbcType=VARCHAR}


   AND HGRK_GRP_C = #{HGRK_GRP_C , jdbcType=VARCHAR}


   AND HGRK_DTL_C = #{HGRK_DTL_C , jdbcType=VARCHAR}


   AND HGRK_GRP_C = #{HRNK_RBA_RSK_C , jdbcType=VARCHAR}
   AND HGRK_DTL_C = #{HRNK_RBA_RSK_C_V , jdbcType=VARCHAR}

ORDER BY SNO

