UPDATE SRBA2_RISK_WEGHT_M
    SET RSK_WEGHT = CASE 
        WHEN RSK_WEIGHT_KIND_C = 1 THEN #{RSK_RT, jdbcType=VARCHAR}
        WHEN RSK_WEIGHT_KIND_C = 2 THEN #{RSK_NAT_RT, jdbcType=VARCHAR}
        WHEN RSK_WEIGHT_KIND_C = 3 THEN #{RSK_CUST_RT, jdbcType=VARCHAR}
        WHEN RSK_WEIGHT_KIND_C = 4 THEN #{RSK_PROD_RT, jdbcType=VARCHAR}
        WHEN RSK_WEIGHT_KIND_C = 5 THEN #{RSK_TRN_RT, jdbcType=VARCHAR}
    END
        WHERE RSK_WEIGHT_KIND_C in (1, 2, 3, 4, 5) AND VALT_YYMM = #{VALT_YYMM, jdbcType=VARCHAR}

UPDATE SRBA2_RISK_ELMT_M SET RSK_WEGHT = 
((H_RSK_YN + WLF_YN) * 2 + 1) * 
    (
        CASE 
            WHEN RSK_CATG_C = 'R1' THEN #{RSK_NAT_RT, jdbcType=VARCHAR}
            WHEN RSK_CATG_C = 'R2' THEN #{RSK_CUST_RT, jdbcType=VARCHAR}
            WHEN RSK_CATG_C = 'R3' THEN #{RSK_PROD_RT, jdbcType=VARCHAR}
            WHEN RSK_CATG_C = 'R4' THEN #{RSK_TRN_RT, jdbcType=VARCHAR}
        END
    ) / 
    (
        CASE 
            WHEN RSK_CATG_C = 'R1' THEN (
                SELECT SUM((H_RSK_YN + WLF_YN) * 2 + 1)
                FROM SRBA2_RISK_ELMT_M
                WHERE RSK_CATG_C = 'R1' AND VALT_YYMM = #{VALT_YYMM, jdbcType=VARCHAR}
            )
            WHEN RSK_CATG_C = 'R2' THEN (
                SELECT SUM((H_RSK_YN + WLF_YN) * 2 + 1)
                FROM SRBA2_RISK_ELMT_M
                WHERE RSK_CATG_C = 'R2' AND VALT_YYMM = #{VALT_YYMM, jdbcType=VARCHAR}
            )
            WHEN RSK_CATG_C = 'R3' THEN (
                SELECT SUM((H_RSK_YN + WLF_YN) * 2 + 1)
                FROM SRBA2_RISK_ELMT_M
                WHERE RSK_CATG_C = 'R3' AND VALT_YYMM = #{VALT_YYMM, jdbcType=VARCHAR}
            )
            WHEN RSK_CATG_C = 'R4' THEN (
                SELECT SUM((H_RSK_YN + WLF_YN) * 2 + 1)
                FROM SRBA2_RISK_ELMT_M
                WHERE RSK_CATG_C = 'R4' AND VALT_YYMM = #{VALT_YYMM, jdbcType=VARCHAR}
            )
        END
    )
WHERE VALT_YYMM = #{VALT_YYMM, jdbcType=VARCHAR}

