SELECT A.VALT_BRNO_C AS BRNO_CD , B.MOFC_BRN_CCD AS BRNO_TYPE_CD , GET_CODE_NAME('M043', B.MOFC_BRN_CCD) AS BRNO_TYPE , B.DPRT_NM AS BRNO_NM FROM SRBA2_DEPT_MNT A INNER JOIN NIC41B B ON A.VALT_BRNO_C = B.DPRT_CD WHERE VALT_YYMM = #{VALT_YYMM, jdbcType=VARCHAR}
AND B.MOFC_BRN_CCD = #{BRNO_TYPE}
AND (B.DPRT_NM LIKE '%' || #{BRNO_NM} || '%' OR B.DPRT_CD LIKE '%' || #{BRNO_NM} || '%')

SELECT A.DPRT_CD AS BRNO_CD , A.MOFC_BRN_CCD AS BRNO_TYPE_CD , GET_CODE_NAME('M043', A.MOFC_BRN_CCD) AS BRNO_TYPE , A.DPRT_NM AS BRNO_NM FROM NIC41B A WHERE A.DPRT_CD NOT IN ( SELECT B.VALT_BRNO_C FROM SRBA2_DEPT_MNT B WHERE B.VALT_YYMM = #{VALT_YYMM} )
AND (A.DPRT_NM LIKE '%' || #{BRNO_NM} || '%' OR A.DPRT_CD LIKE '%' || #{BRNO_NM} || '%')
AND A.MOFC_BRN_CCD = #{BRNO_TYPE}

SELECT DISTINCT A.VALT_YYMM as VALT_YYMM , A.RSK_CATG_C as RSK_CATG_C , (SELECT DTL_C_NM AS NAME FROM SRBA2_DTL_C WHERE USYN=1 AND GRP_C='R502' AND DTL_C= A.RSK_CATG_C ) AS RSK_CATG_C_NM , B.RSK_FIX_YN as RSK_FIX_YN FROM SRBA2_RISK_ELMT_M A JOIN SRBA2_VLTN_SCE_M B on A.VALT_YYMM = B.VALT_YYMM WHERE A.VALT_YYMM = #{VALT_YYMM, jdbcType=VARCHAR}
AND A.RSK_CATG_C = #{RSK_CATG_C, jdbcType=VARCHAR}
ORDER BY A.RSK_CATG_C

SELECT CASE WHEN COUNT(1) = 0 THEN 'Y' ELSE 'N' END AS CREATE_YN
  FROM SRBA2_RISK_ELMT_M
 WHERE 1=1
   AND VALT_YYMM            = #{VALT_YYMM, jdbcType=VARCHAR}
   AND RSK_CATG_C           = #{RSK_CATG_C, jdbcType=VARCHAR} 
   AND RSK_ELMT_C           = #{RSK_ELMT_C, jdbcType=VARCHAR}

SELECT A.VALT_YYMM , A.RSK_ELMT_C , (SELECT DTL_C_NM AS NAME FROM SRBA2_DTL_C WHERE USYN=1 AND GRP_C='R503' AND DTL_C= A.RSK_ELMT_C ) AS RSK_ELMT_C_NM , A.RSK_ELMT_DTL_CTNT , case A.NORM_YN when 1 then 'Y' Else 'N' end NORM_YN , A.RSK_CATG_C , (SELECT DTL_C_NM AS NAME FROM SRBA2_DTL_C WHERE USYN=1 AND GRP_C='R502' AND DTL_C= A.RSK_CATG_C ) RSK_CATG_C_NM , A.RSK_WEGHT , A.H_RSK_YN , A.WLF_YN , B.RSK_SCNR_I as RSK_SCNR_I , A.RSK_CTNT , A.CAL_METH_CTNT , A.KRI_CAL_METH_CTNT , C.RSK_FIX_YN as RSK_FIX_YN , TO_CHAR(TO_DATE(C.DR_DT, 'YYYYMMDD'), 'YYYY-MM-DD') AS DR_DT , TO_CHAR(TO_DATE(C.CHG_DT, 'YYYYMMDD'), 'YYYY-MM-DD') AS CHG_DT FROM SRBA2_RISK_ELMT_M A JOIN SRBA2_VLTN_SCE_M C ON A.VALT_YYMM = C.VALT_YYMM LEFT OUTER JOIN (SELECT X.VALT_YYMM, X.RSK_CATG_C, X.RSK_ELMT_C, NVL(LISTAGG(X.SCNR_ID, ',') WITHIN GROUP (ORDER BY X.SCNR_ID), '') AS RSK_SCNR_I FROM SRBA2_RISK_SCNR_I X WHERE X.VALT_YYMM = #{VALT_YYMM, JDBCTYPE=VARCHAR} GROUP BY X.VALT_YYMM, X.RSK_CATG_C, X.RSK_ELMT_C ) B ON A.VALT_YYMM = B.VALT_YYMM AND A.RSK_CATG_C = B.RSK_CATG_C AND A.RSK_ELMT_C = B.RSK_ELMT_C WHERE A.VALT_YYMM = #{VALT_YYMM, jdbcType=VARCHAR}
AND A.RSK_CATG_C = #{RSK_CATG_C, jdbcType=VARCHAR}
AND A.RSK_ELMT_C = #{RSK_ELMT_C, jdbcType=VARCHAR}
ORDER BY A.RSK_CATG_C, A.RSK_ELMT_C

