             #{VALT_YYMM, jdbcType=VARCHAR}
           , #{RSK_CATG_C, jdbcType=VARCHAR}
           , #{RSK_ELMT_C, jdbcType=VARCHAR}
           , #{RSK_WEGHT, jdbcType=INTEGER}
           , #{RSK_ELMT_DTL_CTNT, jdbcType=VARCHAR}
           , #{RSK_CTNT, jdbcType=VARCHAR}
           , #{CAL_METH_CTNT, jdbcType=VARCHAR}
           , #{KRI_CAL_METH_CTNT, jdbcType=VARCHAR}
           , #{H_RSK_YN, jdbcType=VARCHAR}
           , #{WLF_YN, jdbcType=VARCHAR}
           , #{NORM_YN, jdbcType=VARCHAR}
           , TO_CHAR(SYSDATE, 'YYYYMMDD')
           , TO_CHAR(SYSDATE, 'HH24MISS')
           , #{DR_OP_JKW_NO, jdbcType=VARCHAR}
           )

UPDATE SRBA2_RISK_ELMT_M A
   SET A.RSK_WEGHT = ((A.H_RSK_YN + A.WLF_YN) * 2 + 1)
                 * (
                     SELECT B.RSK_WEGHT
                       FROM SRBA2_RISK_WEGHT_M B
                      WHERE B.RSK_WEIGHT_KIND_C = CASE A.RSK_CATG_C
                                                       WHEN 'R1' THEN 2
                                                       WHEN 'R2' THEN 3
                                                       WHEN 'R3' THEN 4
                                                       WHEN 'R4' THEN 5
                                                   END
                        AND B.VALT_YYMM = #{VALT_YYMM, jdbcType=VARCHAR}
                   )
                 / (
                     SELECT SUM((H_RSK_YN + WLF_YN) * 2 + 1) 
                       FROM SRBA2_RISK_ELMT_M
                      WHERE RSK_CATG_C = #{RSK_CATG_C, jdbcType=VARCHAR}
                        AND VALT_YYMM = #{VALT_YYMM, jdbcType=VARCHAR}
                   )
 WHERE RSK_CATG_C = #{RSK_CATG_C, jdbcType=VARCHAR}
   AND VALT_YYMM = #{VALT_YYMM, jdbcType=VARCHAR}

