mapper.select:
SELECT DISTINCT A.VALT_YYMM as VALT_YYMM , A.CNTL_CATG_C as CNTL_CATG_C , (SELECT DTL_C_NM AS NAME FROM SRBA2_DTL_C WHERE USYN=1 AND GRP_C='R504' AND DTL_C= A.CNTL_CATG_C ) AS CNTL_CATG_C_NM , B.TONGJE_FIX_YN as TONGJE_FIX_YN FROM SRBA2_CNTL_ELMN_M A JOIN SRBA2_VLTN_SCE_M B on A.VALT_YYMM = B.VALT_YYMM WHERE A.VALT_YYMM = #{VALT_YYMM, jdbcType=VARCHAR}
AND A.CNTL_CATG_C = #{CNTL_CATG_C, jdbcType=VARCHAR}
ORDER BY A.CNTL_CATG_C

SELECT A.VALT_YYMM , A.CNTL_ELMN_C , (SELECT DTL_C_NM AS NAME FROM SRBA2_DTL_C WHERE USYN=1 AND GRP_C='R505' AND DTL_C= A.CNTL_ELMN_C ) AS CNTL_ELMN_C_NM , A.CNTL_ELMN_DTL_CTNT , B.CNTL_ELMN_CNT , CASE WHEN A.NORM_YN = 1 THEN 'Y' ELSE 'N' END NORM_YN , A.CNTL_CATG_C , TO_CHAR(TO_DATE(A.DR_DT, 'YYYYMMDD'), 'YYYY-MM-DD') AS DR_DT , TO_CHAR(TO_DATE(A.CHG_DT, 'YYYYMMDD'), 'YYYY-MM-DD') AS CHG_DT , (SELECT DTL_C_NM AS NAME FROM SRBA2_DTL_C WHERE USYN=1 AND GRP_C='R504' AND DTL_C= A.CNTL_CATG_C ) AS CNTL_CATG_C_NM , C.TONGJE_FIX_YN AS TONGJE_FIX_YN , D.MNG_BRNO_NM AS MNG_BRNO_NM , D.BRNO_TYPE AS BRNO_TYPE FROM SRBA2_CNTL_ELMN_M A INNER JOIN SRBA2_VLTN_SCE_M C ON A.VALT_YYMM = C.VALT_YYMM LEFT JOIN (SELECT X.VALT_YYMM , X.CNTL_CATG_C , X.CNTL_ELMN_C , COUNT(X.CNTL_ELMN_C) AS CNTL_ELMN_CNT FROM SRBA2_CNTL_ITEM_D X WHERE X.VALT_YYMM = #{VALT_YYMM, jdbcType=VARCHAR} GROUP BY X.VALT_YYMM, X.CNTL_CATG_C, X.CNTL_ELMN_C ) B ON A.VALT_YYMM = B.VALT_YYMM AND A.CNTL_CATG_C = B.CNTL_CATG_C AND A.CNTL_ELMN_C = B.CNTL_ELMN_C LEFT JOIN ( SELECT X.VALT_YYMM , X.CNTL_CATG_C , X.CNTL_ELMN_C , CASE WHEN Z.BRNO_TYPE_CD = 'B' THEN '지점' ELSE '본점' END AS BRNO_TYPE , LISTAGG(Y.DPRT_NM, ',') WITHIN GROUP (ORDER BY Y.DPRT_NM) AS MNG_BRNO_NM FROM SRBA2_CNTL_BRNO_I X INNER JOIN NIC41B Y ON X.VALT_BRNO_C = Y.DPRT_CD INNER JOIN SRBA2_DEPT_MNT Z ON X.VALT_YYMM = Z.VALT_YYMM AND X.VALT_BRNO_C = Z.VALT_BRNO_C WHERE X.VALT_YYMM = #{VALT_YYMM, jdbcType=VARCHAR} GROUP BY X.VALT_YYMM, X.CNTL_CATG_C, X.CNTL_ELMN_C, Z.BRNO_TYPE_CD ) D ON A.VALT_YYMM = D.VALT_YYMM AND A.CNTL_CATG_C = D.CNTL_CATG_C AND A.CNTL_ELMN_C = D.CNTL_ELMN_C WHERE A.VALT_YYMM = #{VALT_YYMM, jdbcType=VARCHAR}
AND A.CNTL_CATG_C = #{CNTL_CATG_C, jdbcType=VARCHAR}
AND A.CNTL_ELMN_C = #{CNTL_ELMN_C, jdbcType=VARCHAR}
ORDER BY A.VALT_YYMM, A.CNTL_CATG_C, A.CNTL_ELMN_C

