SELECT ROW_NUMBER() OVER (ORDER BY NULL) AS NO , A.* FROM ( SELECT A.IN_DT ,A.SNO ,A.NEWS_TITE ,A.NEWS_DT ,A.SRC_INFO_C ,(SELECT DTL_C_NM AS NAME FROM SRBA2_DTL_C WHERE USYN=1 AND GRP_C='R510' AND DTL_C= A.SRC_INFO_C ) AS SRC_INFO_NM ,A.URL ,A.NEWS_CTNT ,A.DR_RSN ,A.INDV_CORP_NM ,A.CUST_G_C ,A.STR_RPT_DT ,A.STR_RPT_NO ,A.ATTCH_FILE_NO ,TO_CHAR(TO_DATE(A.DR_DT, 'YYYYMMDD'), 'YYYY-MM-DD') AS DR_DT ,A.DR_TIME ,A.DR_OP_JKW_NO ,(SELECT USER_NM FROM C_USER WHERE LOGIN_ID = A.DR_OP_JKW_NO) AS DR_OP_JKW_NM ,TO_CHAR(TO_DATE(A.CHG_DT, 'YYYYMMDD'), 'YYYY-MM-DD') AS CHG_DT ,A.CHG_TIME ,A.CHG_OP_JKW_NO ,(SELECT USER_NM FROM C_USER WHERE LOGIN_ID = A.CHG_OP_JKW_NO) AS CHG_OP_JKW_NM ,CASE WHEN (SELECT COUNT(ATTCH_FILE_NO) FROM RBA_ATTCH_FILE WHERE ATTCH_FILE_NO=A.ATTCH_FILE_NO) > 0 THEN 'Y' ELSE 'N' END AS ATTATCH_YN FROM SRBA2_ML_EXP_I A WHERE A.NEWS_DT BETWEEN #{stDate, jdbcType=VARCHAR} AND #{edDate, jdbcType=VARCHAR}
AND A.SRC_INFO_C = #{SRC_INFO_C, jdbcType=VARCHAR}
AND A.NEWS_TITE LIKE CONCAT('%', #{NEWS_TITE, jdbcType=VARCHAR}, '%')
AND A.SNO = #{SNO, jdbcType=VARCHAR}
AND A.IN_DT = #{IN_DT, jdbcType=VARCHAR}
ORDER BY NEWS_DT DESC ) A

