mapper.select:
SELECT NVL(D.GYLJ_ID, 0) AS GYLJ_ID /* 결재ID */ , NVL(D.GYLJ_S_C, 0) AS GYLJ_S_C , E.DTL_C_NM AS GYLJ_S_C_NM /* 승인상태 */ , CASE WHEN NVL(D.GYLJ_S_C, 0) = '3' THEN 'Y' /* 결재상태코드(W014) = 3(완료) */ ELSE 'N' END FINL_GYLJ_S /* 최종승인여부 */ , NVL(( SELECT NVL(H.ROLE_ID, 0) AS ROLE_ID FROM SRBA2_GYLJ_H H WHERE H.GYLJ_ID = D.GYLJ_ID AND H.GYLJ_SER = ( SELECT MAX(GYLJ_SER) FROM SRBA2_GYLJ_H WHERE GYLJ_ID = D.GYLJ_ID ) ) , 0) AS GYLJ_ROLE_ID , NVL(D.GYLJ_ROLE_ID , 0) AS NEXT_GYLJ_ROLE_ID ,(SELECT GYLJ_ROLE_ID FROM C_GYLJ_D WHERE GYLJ_LINE_G_C = 'W015' AND SNO = (SELECT MIN(SNO) FROM C_GYLJ_D WHERE GYLJ_LINE_G_C = 'W015' ) ) AS FIRST_GYLJ ,(SELECT GYLJ_ROLE_ID FROM C_GYLJ_D WHERE GYLJ_LINE_G_C = 'W015' AND SNO = (SELECT MAX(SNO) FROM C_GYLJ_D WHERE GYLJ_LINE_G_C = 'W015' )) AS END_GYLJ , (SELECT GYLJ_S_C FROM SRBA_KRI_IMPV_I WHERE BAS_YYMM = DATE_FORMAT(TIMESTAMPADD(MONTH, -3, CONCAT(BAS_YYMM,'01')), '%Y%m') AND RSK_CATG_C = D.RSK_CATG_C AND RSK_ELMT_C = D.RSK_ELMT_C AND QTE_DGE !=0 ) PRE_GYLJ_S_C FROM SRBA_KRI_IMPV_I D LEFT JOIN SRBA2_DTL_C E /* RBA 상세 코드 정보 */ ON E.GRP_C = 'R512' /* 결재상태코드 */ AND NVL(D.GYLJ_S_C, 0) = E.DTL_C /* 결재상태코드 */ WHERE 1 = 1 AND D.BAS_YYMM = #{VALT_YYMM,jdbcType=VARCHAR} /* 평가일자 */ AND D.QTE_DGE !=0
AND RSK_CATG_C = #{RSK_CATG_C, jdbcType=VARCHAR}
AND RSK_ELMT_C = #{RSK_ELMT_C, jdbcType=VARCHAR}

SELECT VALT_YYMM AS CODE, CONCAT(ALT_YYMM, '월') AS NAME FROM SRBA2_VLTN_SCE_M WHERE VALT_YYMM != 999912
AND VALT_YYMM = #{COPY_YYMM, jdbcType=VARCHAR}
GROUP BY VALT_YYMM ORDER BY VALT_YYMM DESC

SELECT A.VALT_YYMM , A.VALT_BRNO_C , C.DPRT_NM || '(' || A.VALT_BRNO_C || ')' AS DEPT_NM , MAX(E.DTL_C_NM) AS BRNO_TYPE_NM , COUNT(1) AS TARGET_CNT , MAX(D.TOT_COMPLETE_CNT) AS COMPLETED_CNT , CASE WHEN SUM(NVL(A.FIX_YN,0)) != 0 THEN 'Y' ELSE 'N' END AS FIX_YN FROM SRBA2_CNTL_I A INNER JOIN SRBA2_DEPT_MNT B ON A.VALT_YYMM = B.VALT_YYMM AND A.VALT_BRNO_C = B.VALT_BRNO_C INNER JOIN NIC41B C ON B.VALT_BRNO_C = C.DPRT_CD INNER JOIN ( SELECT VALT_YYMM , VALT_BRNO_C , SUM(IS_COMPLETE) AS TOT_COMPLETE_CNT FROM (SELECT VALT_YYMM , VALT_BRNO_C , CNTL_CATG_C , CNTL_ELMN_C , CASE WHEN COUNT(1) = SUM(CASE WHEN NORM_YN IS NULL THEN 0 ELSE 1 END) THEN 1 ELSE 0 END AS IS_COMPLETE FROM SRBA2_CNTL_ITEM_I WHERE VALT_YYMM = #{VALT_YYMM,jdbcType=VARCHAR} GROUP BY VALT_YYMM , VALT_BRNO_C , CNTL_CATG_C , CNTL_ELMN_C ) ID GROUP BY VALT_YYMM , VALT_BRNO_C ) D ON A.VALT_YYMM = D.VALT_YYMM AND A.VALT_BRNO_C = D.VALT_BRNO_C INNER JOIN SRBA2_DTL_C E ON B.BRNO_TYPE_CD = E.DTL_C AND E.GRP_C = 'R534' WHERE A.VALT_YYMM = #{VALT_YYMM,jdbcType=VARCHAR}
AND A.VALT_BRNO_C = #{DEPT_CD,jdbcType=VARCHAR}
GROUP BY A.VALT_YYMM , A.VALT_BRNO_C , C.DPRT_NM

SELECT ROW_NUMBER() OVER (ORDER BY NULL) AS CNT
     , VALT_YYMM AS VALT_YYMM
     , CS_NO AS CS_NO
     , CS_NM AS CS_NM
     , NORM_YN AS NORM_YN
  FROM SRBA_V_CNTL_SP_I A  /* RBA_평가_통제샘플 */
 WHERE A.VALT_YYMM = #{VALT_YYMM,jdbcType=VARCHAR}
   AND A.CNTL_CATG_C = #{CNTL_CATG_C, jdbcType=VARCHAR}
   AND A.CNTL_ELMN_C = #{CNTL_ELMN_C, jdbcType=VARCHAR}
   AND A.VALT_BRNO_C = #{VALT_BRNO_C, jdbcType=VARCHAR}
   AND A.SNO = #{SNO, jdbcType=VARCHAR}

SELECT A.VALT_YYMM , A.CNTL_CATG_C , A.CNTL_ELMN_C , A.SNO , A.VALT_BRNO_C
,A.COLUMN_CNT ,  A.COLUMN1_NM , A.COLUMN2_NM , A.COLUMN3_NM , A.COLUMN4_NM
,NVL(B.EXT_SNO,0) EXT_SNO, B.EXT_COLUMN1 , B.EXT_COLUMN2 , B.EXT_COLUMN3 , B.EXT_COLUMN4 , B.NORM_YN
FROM SRBA2_CNTL_ITEM_I A, SRBA_V_CNTL_SP_I B
WHERE 1=1
   AND A.VALT_YYMM = #{VALT_YYMM,jdbcType=VARCHAR}
   AND A.CNTL_CATG_C = #{CNTL_CATG_C, jdbcType=VARCHAR}
   AND A.CNTL_ELMN_C = #{CNTL_ELMN_C, jdbcType=VARCHAR}
   AND A.VALT_BRNO_C = #{VALT_BRNO_C, jdbcType=VARCHAR}
   AND A.SNO = #{SNO, jdbcType=VARCHAR}
   AND A.VALT_YYMM = B.VALT_YYMM(+)
   AND A.CNTL_CATG_C = B.CNTL_CATG_C(+)
   AND A.CNTL_ELMN_C = B.CNTL_ELMN_C(+)
   AND A.SNO = B.SNO(+)


       AND NVL(B.EXT_SNO,0) >= #{EXT_SNO, jdbcType=NUMERIC}

SELECT ROWNUM CNT , A.RSK_CATG_C /*위험범주 */ , ( SELECT DTL_C_NM FROM SRBA2_DTL_C WHERE DTL_C = A.RSK_CATG_C AND GRP_C ='R502' ) RSK_CATG_NM , A.RSK_ELMT_C /*위험요소 */ , ( SELECT DTL_C_NM FROM SRBA2_DTL_C WHERE DTL_C = A.RSK_ELMT_C AND GRP_C ='R503' ) RSK_ELMT_NM , A.KRI_BMM_CNT /*전월건수 */ , A.KRI_TMM_CNT /*당월건수 */ , A.KRI_INDE_RT /* 증감율 */ , A.KRI_TGT_YN /* KRI 대상여부 */ , NVL((SELECT SUM(KRI_TMM_CNT) FROM SRBA_KRI_SCOR_I WHERE SUBSTR(BAS_YYMM,1,4) = SUBSTR(#{BAS_YYMM,jdbcType=VARCHAR},1,4) AND SUBSTR(BAS_YYMM,5,2) IN ( '03' , '06' ,'09','12') AND NOT (SUBSTR(BAS_YYMM,5,2) = '12' AND QTE_DGE != 0) AND RSK_CATG_C = A.RSK_CATG_C AND RSK_ELMT_C = A.RSK_ELMT_C GROUP BY RSK_CATG_C , RSK_ELMT_C),1) YEAR_CNT , NVL((SELECT SUM(KRI_TMM_CNT) FROM SRBA_KRI_SCOR_I WHERE SUBSTR(BAS_YYMM,1,4) = SUBSTR(#{BAS_YYMM,jdbcType=VARCHAR},1,4) AND SUBSTR(BAS_YYMM,5,2) = '03' AND RSK_CATG_C = A.RSK_CATG_C AND RSK_ELMT_C = A.RSK_ELMT_C GROUP BY RSK_CATG_C , RSK_ELMT_C),0) HAF1_CNT , NVL((SELECT SUM(KRI_TMM_CNT) FROM SRBA_KRI_SCOR_I WHERE SUBSTR(BAS_YYMM,1,4) = SUBSTR(#{BAS_YYMM,jdbcType=VARCHAR},1,4) AND SUBSTR(BAS_YYMM,5,2) = '06' AND RSK_CATG_C = A.RSK_CATG_C AND RSK_ELMT_C = A.RSK_ELMT_C GROUP BY RSK_CATG_C , RSK_ELMT_C),0) HAF2_CNT , NVL((SELECT SUM(KRI_TMM_CNT) FROM SRBA_KRI_SCOR_I WHERE SUBSTR(BAS_YYMM,1,4) = SUBSTR(#{BAS_YYMM,jdbcType=VARCHAR},1,4) AND SUBSTR(BAS_YYMM,5,2) = '09' AND RSK_CATG_C = A.RSK_CATG_C AND RSK_ELMT_C = A.RSK_ELMT_C GROUP BY RSK_CATG_C , RSK_ELMT_C),0) HAF3_CNT , NVL((SELECT SUM(KRI_TMM_CNT) FROM SRBA_KRI_SCOR_I WHERE SUBSTR(BAS_YYMM,1,4) = SUBSTR(#{BAS_YYMM,jdbcType=VARCHAR},1,4) AND SUBSTR(BAS_YYMM,5,2) = '12' AND QTE_DGE != 0 AND RSK_CATG_C = A.RSK_CATG_C AND RSK_ELMT_C = A.RSK_ELMT_C GROUP BY RSK_CATG_C , RSK_ELMT_C),0) HAF4_CNT , B.GUBUN_LIST FROM SRBA_KRI_SCOR_I A , (SELECT VALT_YYMM , RSK_CATG_C , RSK_ELMT_C , LISTAGG(GUBUN,',') WITHIN GROUP (ORDER BY VALT_YYMM , RSK_CATG_C ,RSK_ELMT_C) AS GUBUN_LIST FROM ( SELECT A.VALT_YYMM AS VALT_YYMM , A.RSK_CATG_C AS RSK_CATG_C , A.RSK_ELMT_C AS RSK_ELMT_C ,B.GUBUN , COUNT(*) FROM SRBA2_RISK_SCNR_I A , ( SELECT F.GUBUN , C.MA01_6 AS S_ID , (CASE WHEN NVL(C.MA01_6, '') = '' THEN A.BIZ_NM ELSE CONCAT('[', C.MA01_6, ']', A.BIZ_NM) END) AS NAME , (CASE WHEN NVL(C.MA01_6, '') = '' THEN A.BIZ_DESC ELSE CONCAT('[', C.MA01_6, ']', A.BIZ_DESC) END) AS DESCRIPTION FROM C_BIZ A LEFT OUTER JOIN MMA010TB C ON ( A.BIZ_ID=C.RT30_1) , C_PKG_BIZ_MAP B ,(SELECT A.BIZ_ID , (CASE WHEN NVL(C.MA01_6, '') = '' THEN A.BIZ_NM ELSE CONCAT('[', C.MA01_6, ']', A.BIZ_NM) END) AS GUBUN FROM C_BIZ A LEFT OUTER JOIN MMA010TB C ON ( A.BIZ_ID=C.RT30_1) , C_PKG_BIZ_MAP B WHERE B.PKG_ID = 6 AND A.BIZ_ID=B.BIZ_ID AND B.PAR_BIZ_ID=11 AND A.EDIT_YN = 'Y'
AND B.PAR_BIZ_ID <> B.BIZ_ID
ORDER BY C.MA01_6, B.DISPLAY_ORDER ) F WHERE B.PKG_ID = '6' AND A.BIZ_ID=B.BIZ_ID AND B.PAR_BIZ_ID=F.BIZ_ID AND A.EDIT_YN = 'Y'
AND B.PAR_BIZ_ID <> B.BIZ_ID ORDER BY C.MA01_6, B.DISPLAY_ORDER
) B WHERE A.RULE_ID = B.S_ID AND A.VALT_YYMM = (SELECT CASE WHEN (SELECT COUNT(*) FROM SRBA2_RISK_SCNR_I WHERE VALT_YYMM != '999912' AND VALT_YYMM = #{BAS_YYMM,jdbcType=VARCHAR}
) > 0
THEN #{BAS_YYMM,jdbcType=VARCHAR} ELSE (SELECT MAX(VALT_YYMM) FROM SRBA2_RISK_SCNR_I WHERE VALT_YYMM != '999912'
AND VALT_YYMM < #{BAS_YYMM,jdbcType=VARCHAR}
) end FROM dual ) AND A.RSK_CATG_C = 'R4' GROUP BY A.VALT_YYMM , A.RSK_CATG_C ,A.RSK_ELMT_C ,B.GUBUN ) GROUP BY VALT_YYMM , RSK_CATG_C , RSK_ELMT_C ) B WHERE A.BAS_YYMM = #{BAS_YYMM,jdbcType=VARCHAR}
AND A.QTE_DGE != 0
AND A.QTE_DGE = #{DGE}
-- AND A.BAS_YYMM = B.VALT_YYMM(+) AND A.RSK_CATG_C = B.RSK_CATG_C(+) AND A.RSK_ELMT_C = B.RSK_ELMT_C(+)

SELECT * FROM ((SELECT * FROM (SELECT SUBSTR(VALT_YYMM,1,4) AS VALT_YYYY ,RSK_CATG_C ,RSK_ELMT_C ,(SELECT DTL_C_NM FROM SRBA2_DTL_C WHERE GRP_C = 'R502' AND DTL_C = A.RSK_CATG_C) AS RSK_CATG_NM ,(SELECT DTL_C_NM FROM SRBA2_DTL_C WHERE GRP_C = 'R503' AND DTL_C = A.RSK_ELMT_C) AS RSK_ELMT_DTL_CTNT ,NVL(RSK_SCORE, 0) AS RSK_SCORE1 ,NVL((SELECT RSK_SCORE FROM SRBA2_RSK_RSLT WHERE SUBSTR(VALT_YYMM,1,4) = #{VALT_YYYY,jdbcType=VARCHAR} - 1 AND RSK_ELMT_C = A.RSK_ELMT_C ), 0) AS RSK_SCORE2 ,NVL((SELECT RSK_SCORE FROM SRBA2_RSK_RSLT WHERE SUBSTR(VALT_YYMM,1,4) = #{VALT_YYYY,jdbcType=VARCHAR} - 2 AND RSK_ELMT_C = A.RSK_ELMT_C ), 0) AS RSK_SCORE3 ,NVL((SELECT RSK_SCORE FROM SRBA2_RSK_RSLT WHERE SUBSTR(VALT_YYMM,1,4) = #{VALT_YYYY,jdbcType=VARCHAR} - 3 AND RSK_ELMT_C = A.RSK_ELMT_C ), 0) AS RSK_SCORE4 FROM SRBA2_RSK_RSLT A WHERE SUBSTR(VALT_YYMM,1,4) = #{VALT_YYYY,jdbcType=VARCHAR}) B) UNION (SELECT #{VALT_YYYY,jdbcType=VARCHAR} AS VALT_YYYY, 'ALL' AS RSK_CATG_C, '' RSK_ELMT_C, '종합' AS RSK_CATG_NM, '' RSK_ELMNT_DTL_CTNT, SUM(A.RSK_SCORE1) AS RSK_SCORE1, SUM(A.RSK_SCORE2) AS RSK_SCORE2, SUM(A.RSK_SCORE3) AS RSK_SCORE3, SUM(A.RSK_SCORE4) AS RSK_SCORE4 FROM (SELECT SUBSTR(VALT_YYMM,1,4) AS VALT_YYYY ,RSK_CATG_C ,RSK_ELMT_C ,(SELECT DTL_C_NM FROM SRBA2_DTL_C WHERE GRP_C = 'R502' AND DTL_C = A.RSK_CATG_C) AS RSK_CATG_NM ,(SELECT DTL_C_NM FROM SRBA2_DTL_C WHERE GRP_C = 'R503' AND DTL_C = A.RSK_ELMT_C) AS RSK_ELMT_DTL_CTNT ,NVL(RSK_SCORE, 0) AS RSK_SCORE1 ,NVL((SELECT RSK_SCORE FROM SRBA2_RSK_RSLT WHERE SUBSTR(VALT_YYMM,1,4) = #{VALT_YYYY,jdbcType=VARCHAR} - 1 AND RSK_ELMT_C = A.RSK_ELMT_C ), 0) AS RSK_SCORE2 ,NVL((SELECT RSK_SCORE FROM SRBA2_RSK_RSLT WHERE SUBSTR(VALT_YYMM,1,4) = #{VALT_YYYY,jdbcType=VARCHAR} - 2 AND RSK_ELMT_C = A.RSK_ELMT_C ), 0) AS RSK_SCORE3 ,NVL((SELECT RSK_SCORE FROM SRBA2_RSK_RSLT WHERE SUBSTR(VALT_YYMM,1,4) = #{VALT_YYYY,jdbcType=VARCHAR} - 3 AND RSK_ELMT_C = A.RSK_ELMT_C ), 0) AS RSK_SCORE4 FROM SRBA2_RSK_RSLT A WHERE SUBSTR(VALT_YYMM,1,4) = #{VALT_YYYY,jdbcType=VARCHAR}) A)) T WHERE 1 = 1
AND T.RSK_CATG_C = #{RSK_CATG_C}
AND T.RSK_ELMT_C = #{RSK_ELMT_C}

SELECT ROWNUM CNT , A.RSK_CATG_C /*위험범주 */ , ( SELECT DTL_C_NM FROM SRBA2_DTL_C WHERE DTL_C = A.RSK_CATG_C AND GRP_C ='R502' ) RSK_CATG_NM , A.RSK_ELMT_C /*위험요소 */ , ( SELECT DTL_C_NM FROM SRBA2_DTL_C WHERE DTL_C = A.RSK_ELMT_C AND GRP_C ='R503' ) RSK_ELMT_NM , CASE WHEN A.GYLJ_S_C IS NULL THEN '미처리' WHEN A.GYLJ_S_C IN ('1','2') THEN '진행중' WHEN A.GYLJ_S_C IN ('3') THEN '완료' ELSE '미처리' END GYLJ_S_C /*결제진행상태 */ , A.CNFR_ACTN_CTNT /*대응조치*/ , A.FIX_YN FROM SRBA_KRI_IMPV_I A WHERE A.BAS_YYMM = #{BAS_YYMM,jdbcType=VARCHAR}
AND A.QTE_DGE != 0
AND A.QTE_DGE = #{DGE}

SELECT ROWNUM CNT , A.RSK_CATG_C /*위험범주 */ , ( SELECT DTL_C_NM FROM SRBA2_DTL_C WHERE DTL_C = A.RSK_CATG_C AND GRP_C ='R502' ) RSK_CATG_NM , A.RSK_ELMT_C /*위험요소 */ , ( SELECT DTL_C_NM FROM SRBA2_DTL_C WHERE DTL_C = A.RSK_ELMT_C AND GRP_C ='R503' ) RSK_ELMT_NM , (SELECT COUNT(*) FROM SRBA_V_RISK_CUST_I WHERE VALT_YYMM = A.VALT_YYMM AND RSK_CATG_C = A.RSK_CATG_C AND RSK_ELMT_C = A.RSK_ELMT_C AND QTE_DGE = 0 ) AS CUST_CNT /*위험보유고객수*/ , B.KRI_TGT_YN /*red 발생건수*/ FROM SRBA2_RISK_ELMT_M A /*위험요소*/ , SRBA_KRI_SCOR_I B /*KRI점수*/ WHERE A.VALT_YYMM = #{VALT_YYMM,jdbcType=VARCHAR}
AND A.RSK_CATG_C = #{RSK_CATG_C, jdbcType=VARCHAR}
AND A.VALT_YYMM = B.BAS_YYMM AND A.RSK_CATG_C = B.RSK_CATG_C AND A.RSK_ELMT_C = B.RSK_ELMT_C ORDER BY A.RSK_CATG_C , A.RSK_ELMT_C

SELECT A.CNTL_CATG_C /*통제범주 */ , ( SELECT DTL_C_NM FROM SRBA2_DTL_C WHERE DTL_C = A.CNTL_CATG_C AND GRP_C ='R504' ) CNTL_CATG_NM , A.CNTL_ELMN_C /*통제요소 */ , ( SELECT DTL_C_NM FROM SRBA2_DTL_C WHERE DTL_C = A.CNTL_ELMN_C AND GRP_C ='R505' ) CNTL_ELMN_NM , NVL(SUM(USE_YN),0) TOT_CNT , NVL(SUM(NORM_YN),0) Y_CNT , NVL(ROUND((SUM(NORM_YN)/COUNT(1)),2),0)*100 || '%' AS PER_CNT , CASE WHEN NVL(ROUND((SUM(NORM_YN)/COUNT(1)),2),0)*100 > 0 THEN TO_CHAR(B.CATG_RATIO) ELSE TO_CHAR(0) END AS PER_CATG_CNT , ROW_NUMBER() OVER(ORDER BY A.CNTL_CATG_C , A.CNTL_ELMN_C) AS NUM FROM SRBA2_CNTL_ITEM_I A LEFT JOIN (SELECT CNTL_CATG_C , ROUND(SUM(IB.RATIO)/COUNT(1),2) || '%' AS CATG_RATIO /* SUM(요소별 평가비율) / 범주개수 */ FROM ( SELECT CNTL_CATG_C , CNTL_ELMN_C , NVL(ROUND((SUM(NORM_YN)/COUNT(1)),2),0)*100 AS RATIO FROM SRBA2_CNTL_ITEM_I WHERE VALT_YYMM = #{VALT_YYMM,jdbcType=VARCHAR} AND USE_YN = 1 GROUP BY CNTL_CATG_C, CNTL_ELMN_C ) IB GROUP BY IB.CNTL_CATG_C ) B ON A.CNTL_CATG_C = B.CNTL_CATG_C WHERE VALT_YYMM = #{VALT_YYMM,jdbcType=VARCHAR} and A.USE_YN = 1
AND A.CNTL_CATG_C = #{CNTL_CATG_C,jdbcType=VARCHAR}
GROUP BY A.CNTL_CATG_C , A.CNTL_ELMN_C, B.CATG_RATIO

mapper.update:
INSERT INTO SRBA2_GYLJ_H ( GYLJ_ID , GYLJ_SER , GYLJ_G_C , GYLJ_S_C , GYLJ_DT , GYLJ_JKW_NO , ROLE_ID , NOTE_CTNT , DR_DT , DR_TIME , DR_OP_JKW_NO )
SELECT SRBA2_GYLJ_H_SEQ.NEXTVAL AS GYLJ_ID , GYLJ_SER+1 AS GYLJ_SER , GYLJ_G_C , #{GYLJ_S_C, jdbcType=VARCHAR} AS GYLJ_S_C , TO_CHAR(SYSDATE,'YYYYMMDD') AS GYLJ_DT , #{GYLJ_JKW_NO, jdbcType=VARCHAR} AS GYLJ_JKW_NO , #{ROLE_ID, jdbcType=VARCHAR} AS ROLE_ID , NOTE_CTNT , DR_DT , DR_TIME , DR_OP_JKW_NO AS DR_OP_JKW_NO FROM SRBA2_GYLJ_H WHERE GYLJ_ID = #{GYLJ_ID, jdbcType=VARCHAR}
VALUES ( SRBA2_GYLJ_H_SEQ.NEXTVAL , 0 , #{GYLJ_G_C , jdbcType=VARCHAR} , #{GYLJ_S_C , jdbcType=VARCHAR} , TO_CHAR(SYSDATE,'YYYYMMDD') , #{GYLJ_JKW_NO , jdbcType=VARCHAR} , #{ROLE_ID , jdbcType=VARCHAR} , #{NOTE_CTNT , jdbcType=VARCHAR} , TO_CHAR(SYSDATE,'YYYYMMDD') , TO_CHAR(SYSDATE,'HH24MISS') , #{DR_OP_JKW_NO, jdbcType=VARCHAR} )

